import{_ as t,c as i,o as e,a1 as o}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"よくある質問: OAuth 認証とモデルトラブルシューティング | Antigravity Auth","description":"Antigravity Auth プラグインのよくある質問と解決策を理解します。OAuth 認証失敗のトラブルシューティング、モデルが見つからないエラーの処理、プラグイン互換性の設定など、使用中に遭遇する様々な問題を迅速に特定し解決するための実用的なガイドです。","frontmatter":{"title":"よくある質問: OAuth 認証とモデルトラブルシューティング | Antigravity Auth","sidebarTitle":"認証失敗の対処法","subtitle":"よくある質問: OAuth 認証とモデルトラブルシューティング","description":"Antigravity Auth プラグインのよくある質問と解決策を理解します。OAuth 認証失敗のトラブルシューティング、モデルが見つからないエラーの処理、プラグイン互換性の設定など、使用中に遭遇する様々な問題を迅速に特定し解決するための実用的なガイドです。","order":4},"headers":[],"relativePath":"ja/NoeFabris/opencode-antigravity-auth/faq/index.md","filePath":"ja/NoeFabris/opencode-antigravity-auth/faq/index.md"}'),r={name:"ja/NoeFabris/opencode-antigravity-auth/faq/index.md"};function l(d,a,n,h,u,s){return e(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="よくある質問" tabindex="-1">よくある質問 <a class="header-anchor" href="#よくある質問" aria-label="Permalink to &quot;よくある質問&quot;">​</a></h1><p>本セクションでは、Antigravity Auth プラグインを使用する際によく遭遇する問題と解決策をまとめています。OAuth 認証の失敗、モデルリクエストのエラー、プラグインの互換性の問題など、それぞれの問題に対応したトラブルシューティングガイドを提供しています。</p><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">開始前に確認してください</p><ul><li>✅ <a href="/docs/opencodedocs/ja/NoeFabris/opencode-antigravity-auth/start/quick-install/">クイックインストール</a> が完了し、アカウント追加に成功していること</li><li>✅ <a href="/docs/opencodedocs/ja/NoeFabris/opencode-antigravity-auth/start/first-auth-login/">初回認証</a> が完了し、OAuth フローを理解していること</li></ul></div><h2 id="学習ルート" tabindex="-1">学習ルート <a class="header-anchor" href="#学習ルート" aria-label="Permalink to &quot;学習ルート&quot;">​</a></h2><p>遭遇している問題の種類に応じて、適切なトラブルシューティングガイドを選択してください：</p><h3 id="_1-oauth-認証失敗のトラブルシューティング" tabindex="-1">1. <a href="./common-auth-issues/">OAuth 認証失敗のトラブルシューティング</a> <a class="header-anchor" href="#_1-oauth-認証失敗のトラブルシューティング" aria-label="Permalink to &quot;1. [OAuth 認証失敗のトラブルシューティング](./common-auth-issues/)&quot;">​</a></h3><p>OAuth 認証、トークンの更新、アカウント関連の一般的な問題を解決します。</p><ul><li>ブラウザでの認証は成功したが、端末で「認証失敗」と表示される</li><li>突然「Permission Denied」や「invalid_grant」エラーが発生する</li><li>Safari ブラウザで OAuth コールバックが失敗する</li><li>WSL2/Docker 環境で認証を完了できない</li></ul><h3 id="_2-アカウントの移行" tabindex="-1">2. <a href="./migration-guide/">アカウントの移行</a> <a class="header-anchor" href="#_2-アカウントの移行" aria-label="Permalink to &quot;2. [アカウントの移行](./migration-guide/)&quot;">​</a></h3><p>異なるマシン間でアカウントを移行したり、バージョンアップに対応したりします。</p><ul><li>古いコンピュータから新しいコンピュータへアカウントを移転する</li><li>保存形式のバージョン変化（v1/v2/v3）を理解する</li><li>移行後の invalid_grant エラーを解決する</li></ul><h3 id="_3-モデルが見つからないトラブルシューティング" tabindex="-1">3. <a href="./model-not-found/">モデルが見つからないトラブルシューティング</a> <a class="header-anchor" href="#_3-モデルが見つからないトラブルシューティング" aria-label="Permalink to &quot;3. [モデルが見つからないトラブルシューティング](./model-not-found/)&quot;">​</a></h3><p>モデルが見つからない、400 エラーなどのモデル関連の問題を解決します。</p><ul><li><code>Model not found</code> エラーのトラブルシューティング</li><li><code>Invalid JSON payload received. Unknown name &quot;parameters&quot;</code> 400 エラー</li><li>MCP サーバー呼び出し時のエラー</li></ul><h3 id="_4-プラグイン互換性" tabindex="-1">4. <a href="./plugin-compatibility/">プラグイン互換性</a> <a class="header-anchor" href="#_4-プラグイン互換性" aria-label="Permalink to &quot;4. [プラグイン互換性](./plugin-compatibility/)&quot;">​</a></h3><p>oh-my-opencode、DCP などのプラグインとの互換性の問題を解決します。</p><ul><li>プラグインの読み込み順序を正しく設定する</li><li>oh-my-opencode で競合する認証方式を無効化する</li><li>並列プロキシシナリオで PID オフセットを有効化する</li></ul><h3 id="_5-tos-警告" tabindex="-1">5. <a href="./tos-warning/">ToS 警告</a> <a class="header-anchor" href="#_5-tos-警告" aria-label="Permalink to &quot;5. [ToS 警告](./tos-warning/)&quot;">​</a></h3><p>使用リスクを理解し、アカウントの利用停止を防ぎます。</p><ul><li>Google サービス利用規約の制限を理解する</li><li>高リスクシナリオ（新規アカウント、集中的なリクエスト）を識別する</li><li>アカウント停止を回避するベストプラクティスを習得する</li></ul><h2 id="問題の迅速な特定" tabindex="-1">問題の迅速な特定 <a class="header-anchor" href="#問題の迅速な特定" aria-label="Permalink to &quot;問題の迅速な特定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>エラー現象</th><th>推奨リソース</th></tr></thead><tbody><tr><td>認証失敗、認証タイムアウト</td><td><a href="./common-auth-issues/">OAuth 認証失敗のトラブルシューティング</a></td></tr><tr><td>invalid_grant、Permission Denied</td><td><a href="./common-auth-issues/">OAuth 認証失敗のトラブルシューティング</a></td></tr><tr><td>モデルが見つからない、400 エラー</td><td><a href="./model-not-found/">モデルが見つからないトラブルシューティング</a></td></tr><tr><td>他のプラグインとの競合</td><td><a href="./plugin-compatibility/">プラグイン互換性</a></td></tr><tr><td>新しい端末への切り替え、バージョンアップ</td><td><a href="./migration-guide/">アカウントの移行</a></td></tr><tr><td>アカウントセキュリティへの懸念</td><td><a href="./tos-warning/">ToS 警告</a></td></tr></tbody></table><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>問題を解決した後、以下のアクションが可能です：</p><ul><li>📖 <a href="/docs/opencodedocs/ja/NoeFabris/opencode-antigravity-auth/advanced/">高度な機能</a> を読んで、マルチアカウントやセッション復元などの機能を深く理解する</li><li>📚 <a href="/docs/opencodedocs/ja/NoeFabris/opencode-antigravity-auth/appendix/">付録</a> を参照して、アーキテクチャ設計と完全な設定リファレンスを確認する</li><li>🔄 <a href="/docs/opencodedocs/ja/NoeFabris/opencode-antigravity-auth/changelog/">更新ログ</a> をチェックし、最新の機能と変更を把握する</li></ul>',26)])])}const m=t(r,[["render",l]]);export{p as __pageData,m as default};
